package validatorpk

import (
	"testing"

	"github.com/ethereum/go-ethereum/common"
	"github.com/stretchr/testify/require"
)

func TestFromString(t *testing.T) {
	require := require.New(t)
	exp := PubKey{
		Type: Types.MLDSA,
		Raw:  common.FromHex(""),
	}
	{
		got, err := FromString("")
		require.NoError(err)
		require.Equal(exp, got)
	}
	{
		got, err := FromString("")
		require.NoError(err)
		require.Equal(exp, got)
	}
	{
		_, err := FromString("")
		require.Error(err)
	}
	{
		_, err := FromString("0x")
		require.Error(err)
	}
	{
		_, err := FromString("-")
		require.Error(err)
	}
}

func TestString(t *testing.T) {
	require := require.New(t)
	pk := PubKey{
		Type: Types.MLDSA,
		Raw:  common.FromHex(""),
	}
	require.Equal("", pk.String())
}
